import React from 'react';

const ServicesSection = () => {
  // Data for service cards, making it easy to add/remove/edit services
  const services = [
    { number: '01', title: 'Academy', description: 'Your Journey to Skill Enhancement & Continuous Learning' },
    { number: '02', title: 'Marketplace', description: 'Connect, Collaborate, & Create Opportunities with Ease' },
    { number: '03', title: 'Smart Registration', description: 'Seamless Onboarding & Instant Access to Resources' },
    { number: '04', title: 'Employers', description: 'Find Your Fit, Your Way: Connect with Top Talent' },
    { number: '05', title: 'Professionals with Disabilities', description: 'Find Your Fit, Your Way: Inclusive Opportunities' },
  ];

  return (
    <section className="p-6 md:p-12 m-4 md:m-8 bg-white shadow-lg rounded-xl transform transition-all duration-300 hover:shadow-xl">
      <h2 className="text-3xl md:text-5xl font-bold text-center mb-10 text-purple-700 bg-gradient-to-r from-purple-50 to-pink-50 p-3 rounded-lg shadow-inner">
        Our Services, Your Growth
      </h2>

      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-8">
        {services.map((service, index) => (
          <div key={index} className="flex flex-col items-center text-center p-8 bg-gray-50 rounded-2xl shadow-md border border-gray-200 transform transition-all duration-300 hover:shadow-xl hover:border-purple-300 hover:-translate-y-1">
            <span className="text-6xl md:text-7xl font-extrabold text-gray-300 mb-4 drop-shadow-sm">{service.number}</span>
            <h3 className="text-xl md:text-2xl font-bold text-gray-800 mb-2 leading-tight">{service.title}</h3>
            <p className="text-md text-gray-600">{service.description}</p>
          </div>
        ))}
      </div>
    </section>
  );
};

export default ServicesSection;
